import{_ as e,o as l,c as d,a0 as n}from"./chunks/framework.Bogozrur.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"philosophy.md","filePath":"philosophy.md"}'),o={name:"philosophy.md"};function a(i,t,s,r,c,g){return l(),d("div",null,[...t[0]||(t[0]=[n('<h2 id="design-decisions" tabindex="-1">Design Decisions <a class="header-anchor" href="#design-decisions" aria-label="Permalink to &quot;Design Decisions&quot;">​</a></h2><p>Every decision responds to a specific HaxBall environment risk.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Decision</th><th style="text-align:left;">Risk mitigated</th></tr></thead><tbody><tr><td style="text-align:left;">Shadow DOM per window (with CSS namespace fallback)</td><td style="text-align:left;">HaxBall&#39;s global CSS bleeding into overlay elements</td></tr><tr><td style="text-align:left;">Single <code>window.HaxUI</code> namespace</td><td style="text-align:left;">Collisions with HaxBall&#39;s own globals or other scripts</td></tr><tr><td style="text-align:left;"><code>EventGuard</code> with per-event-type policy</td><td style="text-align:left;">Keyboard/mouse events leaking into the game</td></tr><tr><td style="text-align:left;"><code>BASE_Z = 9000</code>, configurable</td><td style="text-align:left;">Overlay windows rendering behind HaxBall&#39;s own menus</td></tr><tr><td style="text-align:left;"><code>MutationObserver</code> in <code>RootMount</code></td><td style="text-align:left;">HaxBall clearing the DOM on room transitions</td></tr><tr><td style="text-align:left;"><code>DOMParser</code> in <code>setContent()</code></td><td style="text-align:left;">XSS when rendering external strings (player names, chat)</td></tr><tr><td style="text-align:left;"><code>WindowHandle._destroyed</code> flag</td><td style="text-align:left;">Safe post-destroy calls — no errors inside game callbacks</td></tr><tr><td style="text-align:left;">Context detection in <code>RootMount.init()</code></td><td style="text-align:left;">Script injected into the wrong frame (iframe environments)</td></tr><tr><td style="text-align:left;">Drag listeners attached/removed per-cycle, outside <code>EventRegistry</code></td><td style="text-align:left;">Registry listeners persist for the window&#39;s lifetime — using them for drag caused the cursor to never release</td></tr><tr><td style="text-align:left;"><code>ButtonInjector</code> targets <code>.header-btns</code> with a <code>MutationObserver</code> fallback</td><td style="text-align:left;">Native button bar not mounted yet when the script runs</td></tr><tr><td style="text-align:left;"><code>buttonBorder: &#39;0&#39;</code> in the HaxBall theme</td><td style="text-align:left;">HaxBall&#39;s native buttons have no border — verified via <code>getComputedStyle()</code> on the live DOM, not assumed</td></tr></tbody></table><hr><h2 id="design-decisions-1" tabindex="-1">Design Decisions <a class="header-anchor" href="#design-decisions-1" aria-label="Permalink to &quot;Design Decisions&quot;">​</a></h2><p>Every decision responds to a specific HaxBall environment risk.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Decision</th><th style="text-align:left;">Risk mitigated</th></tr></thead><tbody><tr><td style="text-align:left;">Shadow DOM per window (with CSS namespace fallback)</td><td style="text-align:left;">HaxBall&#39;s global CSS bleeding into overlay elements</td></tr><tr><td style="text-align:left;">Single <code>window.HaxUI</code> namespace</td><td style="text-align:left;">Collisions with HaxBall&#39;s own globals or other scripts</td></tr><tr><td style="text-align:left;"><code>EventGuard</code> with per-event-type policy</td><td style="text-align:left;">Keyboard/mouse events leaking into the game</td></tr><tr><td style="text-align:left;"><code>BASE_Z = 9000</code>, configurable</td><td style="text-align:left;">Overlay windows rendering behind HaxBall&#39;s own menus</td></tr><tr><td style="text-align:left;"><code>MutationObserver</code> in <code>RootMount</code></td><td style="text-align:left;">HaxBall clearing the DOM on room transitions</td></tr><tr><td style="text-align:left;"><code>DOMParser</code> in <code>setContent()</code></td><td style="text-align:left;">XSS when rendering external strings (player names, chat)</td></tr><tr><td style="text-align:left;"><code>WindowHandle._destroyed</code> flag</td><td style="text-align:left;">Safe post-destroy calls — no errors inside game callbacks</td></tr><tr><td style="text-align:left;">Context detection in <code>RootMount.init()</code></td><td style="text-align:left;">Script injected into the wrong frame (iframe environments)</td></tr><tr><td style="text-align:left;">Drag listeners attached/removed per-cycle, outside <code>EventRegistry</code></td><td style="text-align:left;">Registry listeners persist for the window&#39;s lifetime — using them for drag caused the cursor to never release</td></tr><tr><td style="text-align:left;"><code>ButtonInjector</code> targets <code>.header-btns</code> with a <code>MutationObserver</code> fallback</td><td style="text-align:left;">Native button bar not mounted yet when the script runs</td></tr><tr><td style="text-align:left;"><code>buttonBorder: &#39;0&#39;</code> in the HaxBall theme</td><td style="text-align:left;">HaxBall&#39;s native buttons have no border — verified via <code>getComputedStyle()</code> on the live DOM, not assumed</td></tr></tbody></table>',7)])])}const h=e(o,[["render",a]]);export{f as __pageData,h as default};
